    Thread t = new Thread(new Runnable() {
        public void run() {
            SystemTaskProgress.setStatus(apname, Const.STP_MASSEDIT, "Initializing...", 0, SystemTaskProgress.Status.PROCESSING);

            //Register running service
            EntryManagerReAssignRunningService rs = new EntryManagerReAssignRunningService(form.getUrl());
            LongTermTask ltt= ThreadManager.getInstance().addTask(Thread.currentThread(),apname,"Entry manager reassign:"+form.getUrl());
            RunningServiceRegister.getInstance().addService(apname, rs);
            
            //Find parent forms if any
            Set<Integer> parentFormRootDomainIds = account.getParentFormRootDomainIds(rootDomainId);
            
            List<CellInfo> assignFields = new ArrayList<>();
            List<CellInfo> linkToParentFields = new ArrayList<>();
            Map<CellLocation, CellInfo> formFields = form.getFields();
            for (Map.Entry<CellLocation, CellInfo> e : formFields.entrySet()) {
                CellInfo info = e.getValue();
                if ("1".equals(info.getAttribute("usrref")) || "1".equals(info.getAttribute("grpref"))) {
                    assignFields.add(info);
                }
                
                if (parentFormRootDomainIds != null
                        && (parentFormRootDomainIds.contains(info.getDomainId()) 
                        || parentFormRootDomainIds.contains(Encoder.parseInt(info.getAttribute("s"))) )
                        ) {
                    linkToParentFields.add(info);
                }
            }
            
            
            List<BDBWorkerCommand> unlinkCommands = new ArrayList<>();
            List<BDBWorkerCommand> linkCommands = new ArrayList<>();
            Map<Integer, Set<String>> assignedUsersMap = new HashMap<>();
            BDBWorker worker = new BDBWorker(apname);
            
            try { // try catch ensure every threads release right when they end(whether by exception or anything else)
                
                SystemTaskProgress.setStatus(apname, Const.STP_MASSEDIT, "Start reapplying...", 0, SystemTaskProgress.Status.PROCESSING);
                
                SDBQuery q = new SDBQueryFull(worker);
                SDBNode keyNode, node;

                q.go(rootDomainId);
                while ((keyNode = q.next()) != null){
                    int keyNodeId = keyNode.getId();
                    List<SDBNode> allNodes = q.dipAllNodes(DConst.ENTRY_ENTRY_MANAGER);
                    for (SDBNode n : allNodes) {
                        unlinkCommands.add(new BDBWorkerCommandUnlink(rootDomainId, keyNode.getId(), DConst.ENTRY_ENTRY_MANAGER, n.getId()));
                        Log.createStandardLog().setFilePath(Log.MaintenanceLog.RAGIC_SYSTEM_FIELD_CHANGE_LOG.getFilePath(apname)).info(DConst.ENTRY_ENTRY_MANAGER+" "+apname+"/"+rootDomainId+"/"+keyNode.getId()+"/entryManagerReassignJsp "+n.getValue());
                    }
                    
                    //Find all values in assign fields, which should be added to entry manager 
                    Set<String> assignedUsers = new HashSet<>();
                    String value;
                    for (CellInfo info : assignFields) {
                        int domainId = info.getDomainId();
                        allNodes = q.dipAllNodes(domainId);
                        for (SDBNode n : allNodes) {
                            value = n.getValue();
                            if ("1".equals(info.getAttribute("grpref"))) value = "@" + value;
                            assignedUsers.add(value);
                        }
                    }
                    
                    node = q.dipNode(DConst.ENTRY_ORIGINAL_CREATE_USER);
                    if (node != null) { //[BugId:10917]
                        value = node.getValue();
                        assignedUsers.add(value);
                    }
                    
                    assignedUsersMap.put(keyNodeId, assignedUsers);
                    
                    //Get entry manager of parent form
                    if (addParentEntryManager && linkToParentFields.size() > 0) {
                        for (CellInfo linkToParent : linkToParentFields) {
                            int parentRootDomainId = Const.NONODE;
                            if (parentFormRootDomainIds.contains(Encoder.parseInt(linkToParent.getAttribute("s")))) {
                                parentRootDomainId = Encoder.parseInt(linkToParent.getAttribute("s"));
                            }
                            else if (parentFormRootDomainIds.contains(linkToParent.getDomainId())) {
                                parentRootDomainId = linkToParent.getDomainId();
                            }
                            if (parentRootDomainId == Const.NONODE) continue;
                            
                            node = q.dipNode(linkToParent.getDomainId());
                            if (node == null) continue;
                            
                            NodeSource ns = worker.getLinkedNodes(parentRootDomainId, node.getId(), DConst.ENTRY_ENTRY_MANAGER);
                            if (ns == null) continue;
                            SDBNode _node;
                            while ((_node = ns.next()) != null) {
                                linkCommands.add(new BDBWorkerCommandLink(rootDomainId, keyNodeId, DConst.ENTRY_ENTRY_MANAGER, _node.getId()));
                                Log.createStandardLog().setFilePath(Log.MaintenanceLog.RAGIC_SYSTEM_FIELD_CHANGE_LOG.getFilePath(apname)).info(DConst.ENTRY_ENTRY_MANAGER+" "+apname+"/"+rootDomainId+"/"+keyNode.getId()+"/entryManagerReassignJspParent "+_node.getValue());
                            }
                        }
                    }
                }
                
                
            } catch (Exception e) {
            } finally {
                worker.commit();
            }
            
            //unlink
            worker = new BDBWorker(apname);
            int count = 0;
            try{
                for (BDBWorkerCommand c : unlinkCommands) {
                    c.execute(worker);
                    //SystemTaskProgress.setStatus(apname, "Deleted", ++count, false);
                }
            } catch (Exception e) {
            } finally {
                worker.commit();
            }
            
            //addnode + linknode
            worker = new BDBWorker(apname);
            count = 0;
            try{
                for (Map.Entry<Integer, Set<String>> mapEntry : assignedUsersMap.entrySet()) {
                    int keyNodeId = mapEntry.getKey();
                    Set<String> emails = mapEntry.getValue();
                    for (String email : emails) {
                        int nodeId = worker.addNode(DConst.ENTRY_ENTRY_MANAGER, email, true);
                        worker.linkNode(rootDomainId, keyNodeId, DConst.ENTRY_ENTRY_MANAGER, nodeId);
                        Log.createStandardLog().setFilePath(Log.MaintenanceLog.RAGIC_SYSTEM_FIELD_CHANGE_LOG.getFilePath(apname)).info(DConst.ENTRY_ENTRY_MANAGER+" "+apname+"/"+rootDomainId+"/"+keyNodeId+"/entryManagerReassignJspAssignedUsersMap "+email);
                    }
                    SystemTaskProgress.setStatus(apname, Const.STP_MASSEDIT, "Assigned", ++count, SystemTaskProgress.Status.PROCESSING);
                }
                
                for (BDBWorkerCommand c : linkCommands) {
                    c.execute(worker);
                }
            } catch (Exception e) {
            } finally {
                worker.commit();
                RunningServiceRegister.getInstance().removeService(apname, rs);
                ThreadManager.getInstance().removeTask(ltt);
                systemCache.remove(cacheSignature);
                SystemTaskProgress.setStatus(apname, Const.STP_MASSEDIT, "Reassign complete!", -1, SystemTaskProgress.Status.DONE);
            }
        }
    });
    t.setName("Reassign:" + apname + path + "/" + sheetIndex + " " + user.getUserId());
    t.start();

